import { createClient } from 'https://esm.sh/@supabase/supabase-js@2.39.7';

Deno.serve(async (req) => {
  const reqId = Math.random().toString(36).substring(7);
  console.log(`[DIAGNOSTIC][${reqId}] Audit request received.`);

  const supabase = createClient(
    Deno.env.get('SUPABASE_URL')!,
    Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
  );

  try {
    const body = await req.json().catch(() => ({}));
    const { action } = body;

    // ==========================================
    // DEFAULT BEHAVIOR: DEEP SYSTEM AUDIT
    // ==========================================

    console.log(`[DIAGNOSTIC][${reqId}] Fetching Database Stats...`);
    const { data: dbFiles, error: dbErr } = await supabase
      .from('validation_tracking')
      .select('file_path, status, last_error');

    if (dbErr) throw dbErr;

    console.log(`[DIAGNOSTIC][${reqId}] Fetching Storage Bucket List...`);
    const { data: storageFiles, error: storageErr } = await supabase
      .storage
      .from('inspection_bucket')
      .list('', { limit: 1000, sortBy: { column: 'name', order: 'asc' } });

    if (storageErr) throw storageErr;

    const dbPaths = new Set(dbFiles.map(f => f.file_path));
    const storagePaths = new Set(storageFiles?.map(f => f.name) || []);

    // Breakdown DB by status
    const stats = dbFiles.reduce((acc: any, curr: any) => {
      acc[curr.status] = (acc[curr.status] || 0) + 1;
      return acc;
    }, {});

    // Find Mismatches
    const inDbButMissingInStorage = dbFiles.filter(f => !storagePaths.has(f.file_path)).map(f => f.file_path);
    const inStorageButMissingInDb = storageFiles?.filter(f => !dbPaths.has(f.name)).map(f => f.name) || [];

    // Specific check for the '47701' issue
    const sampleFile = 'batch_47701_to_47800.txt';
    const sampleExistsInStorage = storagePaths.has(sampleFile);
    const sampleEntryInDb = dbFiles.find(f => f.file_path === sampleFile);

    console.log(`[DIAGNOSTIC][${reqId}] Audit Complete. Mismatches found: ${inDbButMissingInStorage.length}`);

    const auditReport = {
      summary: {
        total_in_db: dbFiles.length,
        total_in_storage: storageFiles?.length || 0,
        status_breakdown: stats
      },
      mismatch_alerts: {
        count_missing_from_storage: inDbButMissingInStorage.length,
        examples_missing_from_storage: inDbButMissingInStorage.slice(0, 10),
        count_untracked_in_storage: inStorageButMissingInDb.length,
        examples_untracked_in_storage: inStorageButMissingInDb.slice(0, 10)
      },
      specific_sample_check: {
        filename: sampleFile,
        exists_in_storage: sampleExistsInStorage,
        db_entry: sampleEntryInDb || 'NOT_FOUND_IN_DB'
      },
      storage_metadata: storageFiles?.slice(0, 5).map(f => ({
        name: f.name,
        id: f.id,
        metadata: f.metadata ? 'Present' : 'Missing'
      }))
    };

    // If the user adds 'fix: true', we wipe the bad rows
    if (body.action === 'clean_mismatches') {
       console.log(`[DIAGNOSTIC][${reqId}] ACTION: CLEAN_MISMATCHES triggered.`);
       if (inDbButMissingInStorage.length > 0) {
         const { error: delErr } = await supabase
           .from('validation_tracking')
           .delete()
           .in('file_path', inDbButMissingInStorage);

         return new Response(JSON.stringify({ 
           message: `Deleted ${inDbButMissingInStorage.length} ghost records.`, 
           deleted: inDbButMissingInStorage 
         }));
       }
    }

    return new Response(JSON.stringify(auditReport), {
      headers: { 'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*' }
    });

  } catch (err) {
    console.error(`[DIAGNOSTIC][${reqId}] Fatal:`, err);
    return new Response(JSON.stringify({ error: err.message }), { status: 500 });
  }
});

