1366 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
1367 |     function applyLocalPatch(content, ops) {
1368 |         let lines = content.split('\n');
1369 |         let logs = [];
1370 |         let success = true;
1371 | 
1372 |         if (typeof ops === 'string') {
1373 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
1374 |         }
1375 | 
1376 |         ops.forEach(op => {
1377 |             if (op.action === 'comment') return;
1378 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
1379 |             
1380 |             if (op.action === 'replace_block') {
1381 |                 // Strategy 1: Exact String Match (Fastest)
1382 |                 const currentStr = lines.join('\n');
1383 |                 if (currentStr.includes(op.find_block)) {
1384 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
1385 |                     logs.push('Exact match applied');
1386 |                     return;
1387 |                 }
1388 | 
1389 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
1390 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
1391 |                 if (searchLines.length === 0) return;
1392 | 
1393 |                 let matchStart = -1;
1394 |                 let matchEnd = -1;
1395 | 
1396 |                 // Scan file lines
1397 |                 for (let i = 0; i < lines.length; i++) {
1398 |                     // If first line matches (ignoring whitespace)
1399 |                     if (lines[i].trim() === searchLines[0]) {
1400 |                         // Check subsequent lines
1401 |                         let allMatch = true;
1402 |                         let fileOffset = 0;
1403 |                         let searchOffset = 1;
1404 |                         
1405 |                         while (searchOffset < searchLines.length) {
1406 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
1407 |                             const nextFile = lines[i + fileOffset + 1].trim();
1408 |                             // Skip empty lines in file if they aren't in search block
1409 |                             if (nextFile === '') {
1410 |                                 fileOffset++;
1411 |                                 continue;
1412 |                             }
1413 |                             if (nextFile !== searchLines[searchOffset]) {
1414 |                                 allMatch = false;
1415 |                                 break;
1416 |                             }
1417 |                             fileOffset++;
1418 |                             searchOffset++;
1419 |                         }
1420 | 
1421 |                         if (allMatch) {
1422 |                             matchStart = i;
