1431 |                     const replacement = op.replace_with.split('\n');
1432 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
1433 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
1434 |                 } else {
1435 |                     success = false;
1436 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
