3498 |     function formatBytes(bytes) {
3499 |         if (!bytes) return '0 B';
3500 |         const k = 1024;
3501 |         const sizes = ['B', 'KB', 'MB', 'GB'];
3502 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
3503 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
