3506 |     function timeAgo(dateString) {
3507 |         const date = new Date(dateString);
3508 |         const now = new Date();
3509 |         const seconds = Math.floor((now - date) / 1000);
3510 |         if (seconds < 10) return 'just now';
3511 |         if (seconds < 60) return seconds + 's ago';
3512 |         const minutes = Math.floor(seconds / 60);
3513 |         if (minutes < 60) return minutes + 'm ago';
3514 |         const hours = Math.floor(minutes / 60);
3515 |         if (hours < 24) return hours + 'h ago';
3516 |         return date.toLocaleDateString();
3517 |     }
