            // File doesn't exist, but we have boilerplate. This is a NEW function.
            if (isDefaultTemplate) {
                console.log("Detected new function creation from template.");
                status.innerText = "🆕 Preparing new function...";
                isFreshCode = true;
            } else {
                throw new Error("Source not found.");
            }
        }
     } catch (e) {
        // Handle total failure (like 404 or network error)
        if (isDefaultTemplate) {
            console.log("File not found on GitHub, proceeding as new creation.");
            isFreshCode = true;
        } else {
            return alert(`Cannot deploy: Could not verify '${name}'. ` + e.message);
        }
     }
}

