.miron-portal-container {
    width: 95%; /* Wider to allow peeking */
    max-width: 800px;
    margin: 3em auto;
    font-family: 'Poppins', sans-serif;
    font-size: ${baseFontSize}px; /* Dynamic Base */
    position: relative;
    z-index: 100;

    /* HORIZONTAL CAROUSEL SETUP */
    display: flex;
    flex-direction: row;
    gap: 1em;
    overflow-x: auto;
    scroll-snap-type: x mandatory;
    padding-bottom: 1em; /* Space for scrollbar/touch area */

    /* Hide Scrollbar for cleaner look */
    scrollbar-width: none; /* Firefox */
    -ms-overflow-style: none; /* IE/Edge */
}
.miron-portal-container::-webkit-scrollbar { display: none; }

/* Visual Arrow Hint via CSS */
.miron-portal-container::after {
    content: '➜';
    position: absolute;
    right: 0;
    top: 50%;
    transform: translateY(-50%);
    font-size: 2em;
    color: #42d7b8;
    opacity: 0.5;
    pointer-events: none;
    animation: bounce-right 2s infinite;
    text-shadow: 0 0 10px rgba(0,0,0,0.8);
