ops.content:
/* --- MIRON NEURAL INTERFACE --- */
.miron-chat-overlay {
    position: fixed;
    inset: 0;
    z-index: 5000;
    background-color: #050505;
    color: #e0e0e0;
    font-family: 'Poppins', sans-serif;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    animation: fadeInMiron 0.4s ease-out;
}

@keyframes fadeInMiron {
    from { opacity: 0; transform: scale(1.05); }
    to { opacity: 1; transform: scale(1); }
}

/* --- NEURAL NEBULA BACKGROUND --- */
.nebula-bg {
    position: absolute;
    inset: 0;
    z-index: -1;
    background: radial-gradient(circle at 50% 50%, #0a0a0a 0%, #050505 100%);
}

.nebula-orb {
    position: absolute;
    border-radius: 50%;
    filter: blur(80px);
    opacity: 0.12;
    animation: nebulaDrift 20s infinite alternate ease-in-out;
}

.orb-1 { width: 400px; height: 400px; background: #42d7b8; top: -10%; left: -10%; }
.orb-2 { width: 350px; height: 350px; background: #9b59b6; bottom: -5%; right: -5%; animation-delay: -5s; }
.orb-3 { width: 250px; height: 250px; background: #ffcf7d; top: 40%; left: 30%; opacity: 0.05; }

@keyframes nebulaDrift {
    from { transform: translate(0, 0) scale(1); }
    to { transform: translate(10%, 15%) scale(1.1); }
}

/* --- HEADER --- */
.miron-header {
    padding: 1.5rem;
    display: flex;
    justify-content: space-between;
    align-items: center;
    backdrop-filter: blur(10px);
    border-bottom: 1px solid rgba(255,255,255,0.05);
}

.miron-identity {
    display: flex;
    align-items: center;
    gap: 0.85rem;
}

.miron-presence-logo {
    width: 36px;
    height: 36px;
    background: linear-gradient(135deg, #42d7b8, #2e5a52);
    border-radius: 10px;
    display: flex;
    align-items: center;
    justify-content: center;
    box-shadow: 0 0 15px rgba(66, 215, 184, 0.3);
}

.miron-header h1 {
    font-family: 'Newsreader', serif;
    font-style: italic;
    font-weight: 400;
    font-size: 1.25rem;
    color: white;
}

.status-pill {
    background: rgba(255,255,255,0.03);
    border: 1px solid rgba(255,255,255,0.08);
    padding: 0.4rem 0.8rem;
    border-radius: 99px;
    font-size: 0.65rem;
    text-transform: uppercase;
    letter-spacing: 1px;
    color: #42d7b8;
    display: flex;
    align-items: center;
    gap: 6px;
}

.status-dot-active {
    width: 6px; height: 6px;
    background: #42d7b8;
    border-radius: 50%;
    box-shadow: 0 0 8px #42d7b8;
    animation: mironPulse 2s infinite;
}

@keyframes mironPulse {
    0% { transform: scale(1); opacity: 1; }
    50% { transform: scale(1.5); opacity: 0.5; }
    100% { transform: scale(1); opacity: 1; }
}

/* --- MESSAGE AREA --- */
.miron-messages-flow {
    flex: 1;
    padding: 1.5rem;
    overflow-y: auto;
    display: flex;
    flex-direction: column;
    gap: 1.5rem;
}

