import React, { useState, useEffect, useRef } from 'react';
import './MironChat.css';

const MironChat = ({ onClose }) => {
    const [messages, setMessages] = useState([
        {
            id: 1,
            sender: 'miron',
            text: "Welcome Alex. I've been analyzing your recent physics modules. There is an interesting pattern in how you approach thermodynamics. How shall we expand your understanding today?",
            thought: "Synchronizing with student cognitive profile..."
        }
    ]);
    const [inputValue, setInputValue] = useState('');
    const [isThinking, setIsThinking] = useState(false);
    const messagesEndRef = useRef(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(() => {
        scrollToBottom();
    }, [messages, isThinking]);

    const thoughtTraces = [
        "Accessing library of universal constants...",
        "Tracing cognitive neural paths...",
        "Synthesizing pedagogical strategies...",
        "Deciphering your current mental model...",
        "Querying historical scientific datasets..."
    ];

    const handleSend = () => {
        if (!inputValue.trim()) return;

        const userMsg = {
            id: Date.now(),
            sender: 'user',
            text: inputValue
        };

        setMessages(prev => [...prev, userMsg]);
        setInputValue('');
        setIsThinking(true);

        // Simulate Miron AI Response
        setTimeout(() => {
            setIsThinking(false);
            const mironResponse = {
                id: Date.now() + 1,
                sender: 'miron',
                text: "That is a fascinating query. When we look at that concept through the lens of entropy, the symmetry becomes clear. Would you like to visualize the molecular chaos?",
                thought: thoughtTraces[Math.floor(Math.random() * thoughtTraces.length)]
            };
            setMessages(prev => [...prev, mironResponse]);
        }, 2500);
    };

    return (
        <div className="miron-chat-overlay">
            <div className="nebula-bg">
                <div className="nebula-orb orb-1"></div>
                <div className="nebula-orb orb-2"></div>
                <div className="nebula-orb orb-3"></div>
            </div>

            <header className="miron-header">
                <div className="miron-identity">
                    <button className="icon-button" onClick={onClose} style={{ marginRight: '0.5rem' }}>
                        <i className="fas fa-chevron-left"></i>
                    </button>
                    <div className="miron-presence-logo">
                        <i className="fa-solid fa-wand-magic-sparkles" style={{ color: '#050505' }}></i>
                    </div>
                    <h1>Miron Presence</h1>
                </div>
                <div className="status-pill">
                    <div className="status-dot-active"></div>
                    Neural Link Active
                </div>
            </header>

            <div className="miron-messages-flow">
                {messages.map((msg) => (
                    <div key={msg.id} className={`msg-bubble-wrap msg-${msg.sender}`}>
                        {msg.sender === 'miron' && msg.thought && (
                            <span className="thought-trace">{msg.thought}</span>
                        )}
                        <div className="bubble-style">
                            {msg.text}
                        </div>
                    </div>
                ))}

                {isThinking && (
                    <div className="msg-bubble-wrap msg-miron">
                        <span className="thought-trace">Processing...</span>
                        <div className="typing-indicator">
                            <div className="dot"></div>
                            <div className="dot"></div>
                            <div className="dot"></div>
                        </div>
                    </div>
                )}
                <div ref={messagesEndRef} />
            </div>

            <div className="miron-input-container">
                <div className="miron-input-dock">
                    <button className="miron-btn" style={{ background: 'transparent', color: '#909090' }}>
                        <i className="fa-solid fa-microphone-lines"></i>
                    </button>
                    <input 
                        type="text" 
                        placeholder="Inquire of the mind..." 
                        value={inputValue}
                        onChange={(e) => setInputValue(e.target.value)}
                        onKeyPress={(e) => e.key === 'Enter' && handleSend()}
                    />
                    <button className="miron-btn btn-send" onClick={handleSend}>
                        <i className="fa-solid fa-paper-plane"></i>
                    </button>
                </div>
            </div>
        </div>
    );
};

export default MironChat;

