}

@keyframes mironFadeIn {
    from { opacity: 0; transform: scale(1.05); }
    to { opacity: 1; transform: scale(1); }
}

/* --- NEURAL NEBULA BACKGROUND --- */
.nebula-bg {
    position: absolute;
    inset: 0;
    z-index: 0;
    background: radial-gradient(circle at 50% 50%, #0a0a0a 0%, #050505 100%);
}

.miron-orb {
    position: absolute;
    border-radius: 50%;
    filter: blur(80px);
    opacity: 0.12;
    animation: mironDrift 20s infinite alternate ease-in-out;
    pointer-events: none;
}

