.miron-orb-2 { width: 400px; height: 400px; background: #9b59b6; bottom: -5%; right: -5%; animation-delay: -5s; }
.miron-orb-3 { width: 300px; height: 300px; background: #ffcf7d; top: 40%; left: 30%; opacity: 0.04; }

@keyframes mironDrift {
    from { transform: translate(0, 0) scale(1); }
    to { transform: translate(10%, 15%) scale(1.1); }
}

