.miron-header {
    padding: 1.5rem 2rem;
    display: flex;
    justify-content: space-between;
    align-items: center;
    backdrop-filter: blur(10px);
    z-index: 10;
    border-bottom: 1px solid rgba(255, 255, 255, 0.05);
}

.miron-identity {
    display: flex;
    align-items: center;
    gap: 1rem;
}

.miron-logo-aura {
    width: 40px; height: 40px;
    background: linear-gradient(135deg, #42d7b8, #2e5a52);
    border-radius: 12px;
    display: flex;
    align-items: center;
    justify-content: center;
    box-shadow: 0 0 20px rgba(66, 215, 184, 0.3);
}

.miron-header h1 {
    font-family: 'Newsreader', serif;
    font-style: italic;
    font-weight: 400;
    font-size: 1.4rem;
