    display: flex;
    flex-direction: column;
    gap: 2rem;
    z-index: 1;
    scroll-behavior: smooth;
}

.miron-messages-flow::-webkit-scrollbar { width: 0; }

.msg-entry {
    max-width: 85%;
    display: flex;
    flex-direction: column;
    animation: msgIn 0.6s cubic-bezier(0.16, 1, 0.3, 1) forwards;
}

@keyframes msgIn {
    from { opacity: 0; transform: translateY(15px); }
    to { opacity: 1; transform: translateY(0); }
}

.msg-entry.ai { align-self: flex-start; }
.msg-entry.user { align-self: flex-end; }

.thought-trace {
    font-family: 'Newsreader', serif;
    font-style: italic;
    color: #909090;
    font-size: 0.85rem;
    margin-bottom: 0.6rem;
    opacity: 0.8;
}

.msg-bubble {
    padding: 1.2rem 1.6rem;
    border-radius: 22px;
    line-height: 1.6;
    font-size: 0.95rem;
    backdrop-filter: blur(12px);
}

.ai .msg-bubble {
    background: rgba(255, 255, 255, 0.03);
    border: 1px solid rgba(255, 255, 255, 0.08);
    border-bottom-left-radius: 4px;
