    border: 1px solid rgba(255, 255, 255, 0.1);
    padding: 0.5rem;
    border-radius: 24px;
    display: flex;
    align-items: center;
    gap: 0.5rem;
    transition: border-color 0.3s;
}

.miron-input-dock:focus-within { border-color: rgba(66, 215, 184, 0.4); }

.miron-input-dock input {
    flex: 1;
    background: transparent;
    border: none;
    outline: none;
    color: white;
    padding: 0.8rem 1rem;
    font-size: 1rem;
}

.miron-send-btn {
    width: 44px; height: 44px;
    border-radius: 18px;
    border: none;
    background: #42d7b8;
    color: #050505;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: transform 0.2s;
