.activity-hub-overlay {
    position: fixed;
    inset: 0;
    z-index: 3000;
    background: rgba(5, 5, 5, 0.8);
    backdrop-filter: blur(15px);
    display: flex;
    justify-content: flex-end;
    animation: hubFadeIn 0.3s ease;
}

@keyframes hubFadeIn { from { opacity: 0; } to { opacity: 1; } }

.pulse-container {
    width: 100%;
    max-width: 450px;
    height: 100%;
    background: #0c0c0c;
    border-left: 1px solid rgba(255, 255, 255, 0.08);
    display: flex;
    flex-direction: column;
    box-shadow: -20px 0 50px rgba(0,0,0,0.5);
    animation: hubSlide 0.5s cubic-bezier(0.16, 1, 0.3, 1);
}

@keyframes hubSlide { from { transform: translateX(100%); } to { transform: translateX(0); } }

.pulse-header {
    padding: 2.5rem 1.5rem 1rem;
    display: flex;
    justify-content: space-between;
    align-items: flex-end;
}

.pulse-header h1 { font-size: 1.8rem; font-weight: 600; letter-spacing: -0.5px; margin: 0; }

.header-controls { display: flex; gap: 1rem; margin-bottom: 5px; }

.control-btn {
    background: none; border: none; color: #909090;
    font-size: 0.75rem; text-transform: uppercase; letter-spacing: 1px;
    cursor: pointer; transition: color 0.2s;
}

.control-btn:hover { color: #42d7b8; }

/* --- SCROLL AREA --- */
.pulse-scroll {
    flex: 1; overflow-y: auto; padding-bottom: 2rem;
    mask-image: linear-gradient(to bottom, transparent, black 5%, black 95%, transparent);
}

.pulse-scroll::-webkit-scrollbar { width: 0; }

.pulse-section-label {
    padding: 1.5rem 1.5rem 0.5rem;
    font-size: 0.7rem; color: #606060;
    text-transform: uppercase; letter-spacing: 2px; font-weight: 600;
}

/* --- NOTIFICATION ITEM --- */
.pulse-item {
    position: relative;
    padding: 1.25rem 1.5rem;
    display: flex; gap: 1rem;
    border-bottom: 1px solid rgba(255, 255, 255, 0.03);
    cursor: pointer; transition: background 0.3s;
}

.pulse-item:hover { background: rgba(255, 255, 255, 0.02); }

.pulse-item.unread::before {
    content: ''; position: absolute;
    left: 0; top: 0; bottom: 0; width: 3px;
    background: var(--category-color); box-shadow: 0 0 15px var(--category-color);
}

.pulse-icon-box {
    width: 44px; height: 44px; border-radius: 14px;
    background: rgba(255, 255, 255, 0.03); border: 1px solid rgba(255, 255, 255, 0.08);
    display: flex; align-items: center; justify-content: center;
    font-size: 1.1rem; color: var(--category-color); flex-shrink: 0;
}

.pulse-content { flex: 1; }

.pulse-meta { display: flex; justify-content: space-between; align-items: center; margin-bottom: 4px; }
.pulse-meta h3 { font-size: 0.95rem; font-weight: 500; margin: 0; }
.pulse-time { font-size: 0.7rem; color: #707070; }

.pulse-desc { font-size: 0.85rem; color: #909090; line-height: 1.4; margin: 0; }

.miron-pulse-insight {
    margin-top: 10px; padding: 10px 12px;
    background: rgba(66, 215, 184, 0.05); border-radius: 8px;
    font-family: 'Newsreader', serif; font-style: italic;
    font-size: 0.85rem; color: #42d7b8; border-left: 1px solid #42d7b8;
}

.pulse-action-row { margin-top: 12px; display: flex; gap: 8px; }

.pulse-btn {
    padding: 6px 14px; border-radius: 8px; font-size: 0.75rem; font-weight: 500;
    cursor: pointer; border: 1px solid rgba(255,255,255,0.08); background: rgba(255,255,255,0.03);
    color: white;
}

.pulse-btn.primary {
    background: var(--category-color); border-color: transparent; color: #000;
}

/* --- TYPES --- */
.type-study { --category-color: #42d7b8; }
.type-social { --category-color: #9b59b6; }
.type-reward { --category-color: #ffcf7d; }
