}

.prism-dock input {
    flex: 1; background: transparent; border: none; outline: none;
    color: white; font-size: 0.95rem; padding: 0 0.5rem;
}

.add-btn {
    width: 40px; height: 40px; border-radius: 50%;
    background: rgba(255,255,255,0.03); border: none; color: #a0a0a0;
    display: flex; align-items: center; justify-content: center; cursor: pointer;
}

.prism-send-btn {
    width: 40px; height: 40px; border-radius: 50%;
    background: #42d7b8; color: #0c0c0c; border: none; cursor: pointer;
