/* --- LAYOUT & MAIN APP STYLES --- */
.app-container {
    height: 100%;
    width: 100%;
    margin: 0 auto;
    position: relative;
    display: flex;
    flex-direction: column;
    background-color: var(--bg-dark);
    transition: all 0.3s ease;
}

