.tab-content .page-content { padding: 1.5rem; } 
.tab-content > .scrollable-content { flex-grow: 1; overflow-y: auto; }
.tab-content > .scrollable-content::-webkit-scrollbar { display: none; }

.icon-button {
    background: none; border: none;
