.icon-color-1 { background: linear-gradient(45deg, #42d7b8, #1a9c8b); } .icon-color-2 { background: linear-gradient(45deg, #9b59b6, #7a3c9b); } .icon-color-3 { background: linear-gradient(45deg, #f1c40f, #c7a10d); } .icon-color-4 { background: linear-gradient(45deg, #e74c3c, #c0392b); } .icon-color-5 { background: linear-gradient(45deg, #3498db, #2980b9); } .icon-color-6 { background: linear-gradient(45deg, #52606d, #3e4c59); }

/* --- HOME TAB STYLES --- */
