const style = document.createElement('style'); style.textContent = `/* --- PRISM CLARITY UI --- */
.user-chat-overlay {
    position: fixed;
    inset: 0;
    z-index: 2100;
    background-color: #0c0c0c;
    color: #ffffff;
    font-family: 'Poppins', sans-serif;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    animation: prismEnter 0.4s cubic-bezier(0.4, 0, 0.2, 1);
}

@keyframes prismEnter { from { opacity: 0; transform: translateY(30px); } to { opacity: 1; transform: translateY(0); } }

/* --- AMBIENT LIGHT LEAKS --- */
.ambient-prism-light {
    position: absolute;
    width: 60vw; height: 60vw;
    background: radial-gradient(circle, rgba(66, 215, 184, 0.12) 0%, transparent 70%);
    top: -20vw; right: -20vw;
    z-index: -1;
    filter: blur(100px);
    pointer-events: none;
}

/* --- HEADER --- */
.prism-header {
    padding: 1.2rem 1.5rem;
    display: flex;
    align-items: center;
    justify-content: space-between;
    background: rgba(12, 12, 12, 0.7);
    backdrop-filter: blur(25px);
    border-bottom: 1px solid rgba(255, 255, 255, 0.08);
    z-index: 100;
}

.contact-profile {
    display: flex; align-items: center; gap: 12px;
}

.avatar-ring {
    position: relative;
    width: 42px; height: 42px;
}

.avatar-ring img {
    width: 100%; height: 100%;
    border-radius: 50%; border: 2px solid rgba(255,255,255,0.1);
    object-fit: cover;
}

.online-dot {
    position: absolute; bottom: 2px; right: 2px;
    width: 10px; height: 10px; background: #42d7b8;
    border: 2px solid #0c0c0c; border-radius: 50%;
}

.contact-details h2 { font-size: 1rem; font-weight: 600; margin: 0; }
.contact-details p { font-size: 0.75rem; color: #42d7b8; margin: 0; }

/* --- CHAT FLOW --- */
.prism-flow {
    flex: 1; padding: 1.5rem; overflow-y: auto;
    display: flex; flex-direction: column; gap: 1.5rem;
}

.date-pill {
    align-self: center; font-size: 0.7rem; color: #a0a0a0;
    text-transform: uppercase; letter-spacing: 1.5px; padding: 0.4rem 1rem;
    background: rgba(255, 255, 255, 0.03); border-radius: 99px;
}

.msg-prism-group {
    display: flex; flex-direction: column; max-width: 80%;
    animation: prismPop 0.3s ease-out forwards;
}

@keyframes prismPop { from { opacity: 0; transform: scale(0.95); } to { opacity: 1; transform: scale(1); } }

.msg-prism-group.sent { align-self: flex-end; align-items: flex-end; }
.msg-prism-group.received { align-self: flex-start; align-items: flex-start; }

.prism-bubble {
    padding: 0.9rem 1.2rem; font-size: 0.92rem; line-height: 1.5;
}

.sent .prism-bubble {
    background: linear-gradient(135deg, #42d7b8 0%, #2e5a52 100%);
    color: #0c0c0c; font-weight: 500;
    border-radius: 20px 20px 4px 20px;
    box-shadow: 0 8px 20px rgba(66, 215, 184, 0.2);
}

.received .prism-bubble {
    background: #161616; border: 1px solid rgba(255,255,255,0.08);
    color: #ffffff; border-radius: 20px 20px 20px 4px;
}

.prism-time {
    font-size: 0.65rem; color: #a0a0a0; margin-top: 5px;
    display: flex; align-items: center; gap: 4px;
}

.media-frame {
    width: 240px; border-radius: 16px; overflow: hidden;
    margin-bottom: 8px; border: 1px solid rgba(255, 255, 255, 0.1);
}

.media-frame img { width: 100%; height: 160px; object-fit: cover; }

/* --- INPUT --- */
.prism-input-wrapper {
