/* --- ASTRAL IDENTITY STYLES --- */
.astral-profile-wrapper {
    display: flex;
    flex-direction: column;
    min-height: 100%;
    background-color: #050505;
}

/* --- HERO SECTION --- */
.astral-hero {
    position: relative;
    height: 380px;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: flex-end;
    padding-bottom: 2.5rem;
    overflow: hidden;
}

.astral-hero-bg {
    position: absolute;
    inset: 0;
    background: url('https://images.unsplash.com/photo-1534796636912-3b95b3ab5986?auto=format&fit=crop&w=1200&q=80');
    background-size: cover;
    background-position: center;
    filter: brightness(0.4) saturate(0.8);
    z-index: 0;
}

.astral-hero-bg::after {
    content: '';
    position: absolute;
    inset: 0;
    background: linear-gradient(to top, #050505 15%, transparent 100%);
}

/* --- IDENTITY CORE --- */
.identity-core {
    position: relative;
    width: 130px;
    height: 130px;
    margin-bottom: 1.5rem;
    z-index: 1;
}

.halo-ring {
    position: absolute;
    inset: -10px;
    border-radius: 50%;
    border: 3px solid transparent;
    background: linear-gradient(#050505, #050505) padding-box,
                linear-gradient(135deg, #42d7b8, #9b59b6) border-box;
    animation: rotateHalo 12s linear infinite;
}

@keyframes rotateHalo { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }

.avatar-main {
    width: 100%;
    height: 100%;
    border-radius: 50%;
    object-fit: cover;
    border: 4px solid #050505;
    position: relative;
    z-index: 2;
}

.lvl-badge {
    position: absolute;
    bottom: -8px;
    left: 50%;
    transform: translateX(-50%);
    background: #ffcf7d;
    color: #000;
    font-size: 0.75rem;
    font-weight: 700;
    padding: 3px 12px;
    border-radius: 99px;
    z-index: 3;
    box-shadow: 0 4px 15px rgba(255, 207, 125, 0.4);
}

.astral-meta {
    text-align: center;
    position: relative;
    z-index: 1;
}

.astral-meta h1 {
    font-size: 2rem;
    font-weight: 600;
    letter-spacing: -0.5px;
    margin-bottom: 0.2rem;
}

.astral-meta p {
    font-family: 'Newsreader', serif;
    font-style: italic;
    color: #42d7b8;
    font-size: 1.1rem;
}

/* --- PORTAL GRID --- */
.portal-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 1.25rem;
    padding: 2rem 1.5rem;
    max-width: 900px;
    margin: 0 auto;
}

.astral-card {
    background: linear-gradient(145deg, rgba(255,255,255,0.05) 0%, rgba(255,255,255,0.01) 100%);
    border: 1px solid rgba(255,255,255,0.08);
    border-radius: 28px;
    padding: 1.5rem;
    display: flex;
    flex-direction: column;
    gap: 1rem;
    cursor: pointer;
    transition: all 0.4s cubic-bezier(0.16, 1, 0.3, 1);
    position: relative;
    overflow: hidden;
}

.astral-card:hover {
    transform: translateY(-8px);
    border-color: var(--card-accent);
    background: rgba(255, 255, 255, 0.05);
    box-shadow: 0 15px 35px rgba(0,0,0,0.3);
}

.astral-card::before {
    content: '';
    position: absolute;
    top: -50%; left: -50%;
    width: 200%; height: 200%;
    background: radial-gradient(circle, var(--card-accent) 0%, transparent 60%);
    opacity: 0;
    transition: opacity 0.4s;
    z-index: 0;
}

.astral-card:hover::before { opacity: 0.15; }

.p-icon-box {
    width: 52px; height: 52px;
    border-radius: 18px;
    background: rgba(255,255,255,0.03);
    display: flex; align-items: center; justify-content: center;
    font-size: 1.4rem;
    color: var(--card-accent);
    position: relative; z-index: 1;
    border: 1px solid rgba(255,255,255,0.05);
}

.p-text-box {
    position: relative; z-index: 1;
}

.p-text-box h3 {
    font-size: 1.1rem; font-weight: 600; margin-bottom: 4px;
}

.p-text-box p {
    font-size: 0.8rem; color: #909090; line-height: 1.4;
}

.type-obs { --card-accent: #9b59b6; }
.type-mission { --card-accent: #ffcf7d; }

/* --- MONOLITH SETTINGS --- */
.monolith-section {
    max-width: 900px;
    margin: 2rem auto 5rem;
    padding: 0 1.5rem;
}

.monolith-label {
    font-size: 0.75rem;
    text-transform: uppercase;
    letter-spacing: 2px;
    color: #909090;
    margin-bottom: 1.25rem;
    display: block;
    padding-left: 0.5rem;
}

.monolith-list {
    background: rgba(255,255,255,0.02);
    border: 1px solid rgba(255,255,255,0.08);
    border-radius: 28px;
    overflow: hidden;
}

.monolith-item {
    display: flex;
    align-items: center;
    padding: 1.3rem 1.6rem;
    gap: 1.25rem;
    border-bottom: 1px solid rgba(255,255,255,0.05);
    transition: all 0.2s;
    cursor: pointer;
    text-decoration: none;
    color: inherit;
}

.monolith-item:last-child { border-bottom: none; }
.monolith-item:hover { background: rgba(255,255,255,0.04); }

.s-icon-wrap { width: 28px; color: #909090; font-size: 1.1rem; text-align: center; }
.s-label-text { flex: 1; font-size: 1rem; font-weight: 400; }
