/* --- BOOK STACK EFFECT --- */
.book-immersive.is-stack::before, 
.book-immersive.is-stack::after {
    content: '';
    position: absolute;
    inset: 0;
    border-radius: inherit;
    background: inherit;
    border: 1px solid rgba(255, 255, 255, 0.05);
    z-index: -1;
    transition: transform 0.4s ease;
}

.book-immersive.is-stack::before {
    transform: translate(4px, -4px);
    filter: brightness(0.8);
}

.book-immersive.is-stack::after {
    transform: translate(8px, -8px);
    filter: brightness(0.6);
}

.book-group:hover .book-immersive.is-stack::before {
    transform: translate(8px, -8px);
}

.book-group:hover .book-immersive.is-stack::after {
    transform: translate(16px, -16px);
}

.book-immersive.is-stack::hidden-label {
    display: none;
}

.book-immersive.is-stack::after {
    /* Add a small decorative emblem to the top book */
    content: 'EXAMS';
    display: flex;
    align-items: center;
    justify-content: center;
    font-family: 'Cinzel', serif;
    font-size: 0.6rem;
    color: var(--linkoin-gold);
    opacity: 0.8;
    letter-spacing: 2px;
    z-index: 5;
    background: none;
    filter: none;
    border: none;
    transform: translate(0);
    text-shadow: 0 2px 4px rgba(0,0,0,0.5);
}

