/* --- ENHANCED VOLUMETRIC BOOK STACK --- */
.book-immersive.is-stack {
    background: linear-gradient(145deg, #3d2b1f, #1a1410) !important;
    border: 1px solid rgba(255, 215, 0, 0.1);
    /* Use multi-layered box shadows to simulate covers of books underneath */
    box-shadow: 
        2px -2px 0 0 #2a1f10, 
        3px -3px 0 0 #eaddcf, /* Page edge 1 */
        5px -5px 0 0 #3d2b1f, /* Cover 2 */
        6px -6px 0 0 #eaddcf, /* Page edge 2 */
        8px -8px 0 0 #2a1f10, /* Cover 3 */
        10px -10px 25px rgba(0,0,0,0.6);
    transform: translateZ(10px);
}

.exam-stack-content {
    height: 100%;
    width: 100%;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
