operations.content:
/* --- ACADEMIC PAVILION UI --- */
.pavilion-overlay {
    position: fixed;
    inset: 0;
    z-index: 2200;
    background-color: #080808;
    color: #e0e0e0;
    font-family: 'Poppins', sans-serif;
    display: flex;
    flex-direction: column;
    animation: pavilionFade 0.4s cubic-bezier(0.16, 1, 0.3, 1);
}

@keyframes pavilionFade { from { opacity: 0; transform: scale(1.02); } to { opacity: 1; transform: scale(1); } }

.pavilion-header {
    padding: 2rem 1.5rem 1rem;
    background: linear-gradient(to bottom, #0c0c0c, transparent);
    flex-shrink: 0;
}

.pav-uni-identity {
    display: flex; align-items: center; gap: 1rem; margin-bottom: 1.5rem;
}

.pav-emblem-sm {
    width: 36px; height: 36px; border-radius: 10px;
    background: #121212; border: 1px solid #42d7b8;
    display: flex; align-items: center; justify-content: center;
    color: #42d7b8; box-shadow: 0 0 15px rgba(66, 215, 184, 0.2);
}

.pav-header-text h1 { font-size: 1.2rem; font-weight: 600; margin: 0; }
.pav-header-text p { font-size: 0.75rem; color: #808080; text-transform: uppercase; letter-spacing: 1px; margin: 0; }

/* --- SEGMENTED CONTROL --- */
.pav-selector-area {
    padding: 0 1.5rem 1.5rem;
    flex-shrink: 0;
}

.pav-segmented-control {
    background: rgba(255, 255, 255, 0.03);
    border: 1px solid rgba(255, 255, 255, 0.06);
    padding: 4px; border-radius: 14px;
    display: flex; position: relative;
}

.pav-segment {
    flex: 1; padding: 10px 0; text-align: center;
    font-size: 0.85rem; font-weight: 500; color: #808080;
    cursor: pointer; z-index: 2; transition: color 0.3s;
}

.pav-segment.active { color: #080808; }

.pav-active-pill {
    position: absolute; top: 4px; left: 4px;
    width: calc(33.33% - 4px); height: calc(100% - 8px);
    background: #42d7b8; border-radius: 10px;
    z-index: 1; transition: transform 0.4s cubic-bezier(0.16, 1, 0.3, 1);
    box-shadow: 0 4px 15px rgba(66, 215, 184, 0.2);
}

/* --- EXAM LIST --- */
.pavilion-scroll {
    flex: 1; overflow-y: auto; padding: 0 1.5rem 2rem;
    display: flex; flex-direction: column; gap: 1rem;
}

.pav-exam-card {
    background: #121212; border: 1px solid rgba(255, 255, 255, 0.06);
    border-radius: 20px; padding: 1.25rem; position: relative;
    overflow: hidden; animation: cardRise 0.5s ease-out forwards;
}

@keyframes cardRise { from { opacity: 0; transform: translateY(15px); } to { opacity: 1; transform: translateY(0); } }

.pav-card-top { display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 0.75rem; }

.pav-course-code {
    font-family: 'Roboto Mono', monospace; font-size: 0.75rem; font-weight: 700;
    color: #42d7b8; background: rgba(66, 215, 184, 0.1); padding: 4px 8px; border-radius: 6px;
}

.pav-year { font-size: 0.8rem; font-weight: 600; color: #808080; }
.pav-exam-title { font-size: 1.1rem; font-weight: 600; margin-bottom: 1rem; line-height: 1.3; color: white; }

.pav-meta-ribbon {
    display: flex; gap: 1.2rem; padding-top: 1rem;
    border-top: 1px solid rgba(255, 255, 255, 0.03);
}

.pav-meta-item {
    display: flex; align-items: center; gap: 6px; font-size: 0.75rem; color: #808080;
}

.pav-meta-item i { color: #42d7b8; }

/* --- LUME GAUGE --- */
.pav-lume-gauge {
    position: absolute; right: 0; top: 0; bottom: 0; width: 4px; background: rgba(255, 255, 255, 0.05);
}

.pav-lume-fill {
    position: absolute; bottom: 0; left: 0; width: 100%; background: #42d7b8; box-shadow: 0 0 10px #42d7b8;
}

.pav-empty { text-align: center; padding: 4rem 2rem; color: #555; font-style: italic; }

import React, { useState, useEffect } from 'react';
import './ExamPavilion.css';

const ExamPavilion = ({ university, onClose }) => {
    const [exams, setExams] = useState([]);
    const [loading, setLoading] = useState(true);
    const [activeTab, setActiveTab] = useState('Midterm'); // 'Midterm', 'Final', 'Mock'

    useEffect(() => {
        setLoading(true);
        fetch('https://xvldfsmxskhemkslsbym.supabase.co/functions/v1/book-reader', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ action: 'list_exams', university_id: university.id })
        })
        .then(res => res.json())
        .then(data => {
            if (data.exams) setExams(data.exams);
            setLoading(false);
        })
        .catch(err => {
            console.error(err);
            setLoading(false);
        });
    }, [university.id]);

    const filteredExams = exams.filter(e => 
        activeTab === 'Mock' ? (e.exam_type !== 'Midterm' && e.exam_type !== 'Final') : e.exam_type === activeTab
    );

    const getTabTranslate = () => {
        if (activeTab === 'Midterm') return '0%';
        if (activeTab === 'Final') return '100%';
        return '200%';
    };

    return (
        <div className="pavilion-overlay">
            <header className="pavilion-header">
                <div className="pav-uni-identity">
                    <div className="pav-emblem-sm"><i className="fas fa-landmark"></i></div>
                    <div className="pav-header-text">
                        <h1>{university.name}</h1>
                        <p>Academic Pavilion</p>
                    </div>
                    <button className="icon-button" style={{ marginLeft: 'auto', color: 'white' }} onClick={onClose}>
                        <i className="fas fa-times"></i>
                    </button>
                </div>
            </header>

            <div className="pav-selector-area">
                <div className="pav-segmented-control">
                    <div className="pav-active-pill" style={{ transform: `translateX(${getTabTranslate()})` }}></div>
                    <div className={`pav-segment ${activeTab === 'Midterm' ? 'active' : ''}`} onClick={() => setActiveTab('Midterm')}>Midterm</div>
                    <div className={`pav-segment ${activeTab === 'Final' ? 'active' : ''}`} onClick={() => setActiveTab('Final')}>Final</div>
                    <div className={`pav-segment ${activeTab === 'Mock' ? 'active' : ''}`} onClick={() => setActiveTab('Mock')}>Other</div>
                </div>
            </div>

            <main className="pavilion-scroll">
                {loading ? (
                    <div className="pav-empty">Calibrating focus...</div>
                ) : filteredExams.length > 0 ? (
                    filteredExams.map((exam, idx) => (
                        <div className="pav-exam-card" key={exam.id} style={{ animationDelay: `${idx * 0.1}s` }}>
                            <div className="pav-lume-gauge">
                                <div className="pav-lume-fill" style={{ height: '0%' }}></div>
                            </div>
                            <div className="pav-card-top">
                                <span className="pav-course-code">{exam.course_code || 'EXAM'}</span>
                                <span className="pav-year">{exam.date || '2024'}</span>
                            </div>
                            <h2 className="pav-exam-title">{exam.course_name}</h2>
                            <div className="pav-meta-ribbon">
                                <div className="pav-meta-item"><i className="far fa-clock"></i> {exam.time_allowed_minutes || '90'}m</div>
                                <div className="pav-meta-item"><i className="far fa-file-alt"></i> {exam.total_marks || '100'} Marks</div>
                                <div className="pav-meta-item"><i className="fas fa-bolt"></i> Practice</div>
                            </div>
                        </div>
                    ))
                ) : (
                    <div className="pav-empty">No {activeTab} exams found in this archive.</div>
                )}
            </main>
        </div>
    );
};

export default ExamPavilion;

